import React, { useState } from 'react';
import { X, Loader2 } from 'lucide-react';
import { type ProductionFormData } from '../types';

interface ProductionDetailsModalProps {
    isOpen: boolean;
    onClose: () => void;
    onSubmit: (formData: ProductionFormData) => Promise<void>;
    initialData?: ProductionFormData;
}

const emptyData: ProductionFormData = {
    fighterName: '',
    age: '',
    instagram: '',
    email: '',
    roundsCount: '',
    musicLink: '',
    contact1: '',
    contact2: '',
    cornerColor: '',
    team: '',
    opponentName: '',
    notes: ''
};

export function ProductionDetailsModal({ isOpen, onClose, onSubmit, initialData }: ProductionDetailsModalProps) {
    const [formData, setFormData] = useState<ProductionFormData>(emptyData);

    const [isSubmitting, setIsSubmitting] = useState(false);
    const [error, setError] = useState<string | null>(null);

    React.useEffect(() => {
        if (isOpen) {
            setFormData(initialData ? { ...emptyData, ...initialData } : emptyData);
        } else {
            setFormData(emptyData); // Clear when closing to avoid flickering old data
        }
    }, [isOpen, initialData]);

    if (!isOpen) return null;

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
        const { name, value } = e.target;
        setFormData(prev => ({ ...prev, [name]: value }));
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError(null);
        setIsSubmitting(true);
        try {
            await onSubmit(formData);
            onClose();
        } catch (err: any) {
            setError(err.message || 'Erro ao enviar dados. Tente novamente.');
        } finally {
            setIsSubmitting(false);
        }
    };

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-fade-in font-sans">
            <div className="bg-brand-dark border border-brand-red/30 rounded-2xl shadow-[0_0_40px_rgba(220,38,38,0.2)] w-full max-w-2xl max-h-[90vh] overflow-hidden flex flex-col relative">
                <div className="flex items-center justify-between p-6 border-b border-brand-red/20 bg-black/50">
                    <div>
                        <h2 className="text-2xl font-black font-heading uppercase italic tracking-widest text-white">Detalhes da Produção</h2>
                        <p className="text-sm text-gray-400 mt-1 font-medium">
                            Preencha as informações para a edição do seu Highlight.
                        </p>
                    </div>
                    <button
                        onClick={onClose}
                        className="p-2 text-gray-400 hover:text-brand-red hover:bg-brand-red/10 rounded-full transition-colors"
                    >
                        <X className="w-6 h-6" />
                    </button>
                </div>

                <div className="p-6 overflow-y-auto flex-grow form-scrollbar">
                    {error && (
                        <div className="mb-6 p-4 bg-brand-red/20 text-brand-orange border border-brand-orange/30 rounded-xl text-sm font-bold">
                            {error}
                        </div>
                    )}

                    <form id="production-form" onSubmit={handleSubmit} className="space-y-6">
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                            <div>
                                <label className="block text-sm font-bold font-heading uppercase tracking-wider text-gray-300 mb-2">
                                    Nome do Lutador(a) *
                                </label>
                                <input
                                    type="text"
                                    name="fighterName"
                                    required
                                    value={formData.fighterName}
                                    onChange={handleChange}
                                    className="w-full px-4 py-3 bg-black border border-brand-red/20 text-white rounded-xl focus:ring-2 focus:ring-brand-orange focus:border-brand-orange outline-none transition-all placeholder:text-gray-600"
                                    placeholder="Nome completo ou apelido"
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-bold font-heading uppercase tracking-wider text-gray-300 mb-2">
                                    Idade
                                </label>
                                <input
                                    type="text"
                                    name="age"
                                    value={formData.age}
                                    onChange={handleChange}
                                    className="w-full px-4 py-3 bg-black border border-brand-red/20 text-white rounded-xl focus:ring-2 focus:ring-brand-orange focus:border-brand-orange outline-none transition-all placeholder:text-gray-600"
                                    placeholder="Ex: 25"
                                />
                            </div>
                        </div>

                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                            <div>
                                <label className="block text-sm font-bold font-heading uppercase tracking-wider text-gray-300 mb-2">
                                    Instagram
                                </label>
                                <input
                                    type="text"
                                    name="instagram"
                                    value={formData.instagram}
                                    onChange={handleChange}
                                    className="w-full px-4 py-3 bg-black border border-brand-red/20 text-white rounded-xl focus:ring-2 focus:ring-brand-orange focus:border-brand-orange outline-none transition-all placeholder:text-gray-600"
                                    placeholder="@seu_perfil"
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-bold font-heading uppercase tracking-wider text-gray-300 mb-2">
                                    Email
                                </label>
                                <input
                                    type="email"
                                    name="email"
                                    value={formData.email}
                                    onChange={handleChange}
                                    className="w-full px-4 py-3 bg-black border border-brand-red/20 text-white rounded-xl focus:ring-2 focus:ring-brand-orange focus:border-brand-orange outline-none transition-all placeholder:text-gray-600"
                                    placeholder="seu@email.com"
                                />
                            </div>
                        </div>

                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                            <div>
                                <label className="block text-sm font-bold font-heading uppercase tracking-wider text-gray-300 mb-2">
                                    Número para Contato 1 (WhatsApp) *
                                </label>
                                <input
                                    type="text"
                                    name="contact1"
                                    required
                                    value={formData.contact1}
                                    onChange={handleChange}
                                    className="w-full px-4 py-3 bg-black border border-brand-red/20 text-white rounded-xl focus:ring-2 focus:ring-brand-orange focus:border-brand-orange outline-none transition-all placeholder:text-gray-600"
                                    placeholder="(00) 00000-0000"
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-bold font-heading uppercase tracking-wider text-gray-300 mb-2">
                                    Número para Contato 2
                                </label>
                                <input
                                    type="text"
                                    name="contact2"
                                    value={formData.contact2}
                                    onChange={handleChange}
                                    className="w-full px-4 py-3 bg-black border border-brand-red/20 text-white rounded-xl focus:ring-2 focus:ring-brand-orange focus:border-brand-orange outline-none transition-all placeholder:text-gray-600"
                                    placeholder="(00) 00000-0000 (Opcional)"
                                />
                            </div>
                        </div>

                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                            <div>
                                <label className="block text-sm font-bold font-heading uppercase tracking-wider text-gray-300 mb-2">
                                    Quantos rounds tem/teve sua luta? *
                                </label>
                                <input
                                    type="text"
                                    name="roundsCount"
                                    required
                                    value={formData.roundsCount}
                                    onChange={handleChange}
                                    className="w-full px-4 py-3 bg-black border border-brand-red/20 text-white rounded-xl focus:ring-2 focus:ring-brand-orange focus:border-brand-orange outline-none transition-all placeholder:text-gray-600"
                                    placeholder="Ex: 3 rounds de 5 min"
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-bold font-heading uppercase tracking-wider text-gray-300 mb-2">
                                    Cor do Corner (Canto) *
                                </label>
                                <select
                                    name="cornerColor"
                                    required
                                    value={formData.cornerColor}
                                    onChange={handleChange}
                                    className="w-full px-4 py-3 bg-black border border-brand-red/20 text-white rounded-xl focus:ring-2 focus:ring-brand-orange focus:border-brand-orange outline-none transition-all"
                                >
                                    <option value="" className="bg-brand-dark">Selecione...</option>
                                    <option value="Vermelho" className="bg-brand-dark">Vermelho</option>
                                    <option value="Azul" className="bg-brand-dark">Azul</option>
                                    <option value="Não sei" className="bg-brand-dark">Não sei ao certo</option>
                                </select>
                            </div>
                        </div>

                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                            <div>
                                <label className="block text-sm font-bold font-heading uppercase tracking-wider text-gray-300 mb-2">
                                    Sua Equipe *
                                </label>
                                <input
                                    type="text"
                                    name="team"
                                    required
                                    value={formData.team}
                                    onChange={handleChange}
                                    className="w-full px-4 py-3 bg-black border border-brand-red/20 text-white rounded-xl focus:ring-2 focus:ring-brand-orange focus:border-brand-orange outline-none transition-all placeholder:text-gray-600"
                                    placeholder="Nome da sua equipe"
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-bold font-heading uppercase tracking-wider text-gray-300 mb-2">
                                    Nome do Adversário (Se souber)
                                </label>
                                <input
                                    type="text"
                                    name="opponentName"
                                    value={formData.opponentName}
                                    onChange={handleChange}
                                    className="w-full px-4 py-3 bg-black border border-brand-red/20 text-white rounded-xl focus:ring-2 focus:ring-brand-orange focus:border-brand-orange outline-none transition-all placeholder:text-gray-600"
                                    placeholder="Nome do oponente"
                                />
                            </div>
                        </div>

                        <div>
                            <label className="block text-sm font-bold font-heading uppercase tracking-wider text-gray-300 mb-2">
                                Link da Música do YouTube para o Vídeo
                            </label>
                            <input
                                type="url"
                                name="musicLink"
                                value={formData.musicLink}
                                onChange={handleChange}
                                className="w-full px-4 py-3 bg-black border border-brand-red/20 text-white rounded-xl focus:ring-2 focus:ring-brand-orange focus:border-brand-orange outline-none transition-all placeholder:text-gray-600"
                                placeholder="https://www.youtube.com/watch?v=..."
                            />
                            <p className="text-xs text-brand-orange/80 mt-1 font-medium">Insira o link da música que deseja no fundo do seu Highlight.</p>
                        </div>

                        <div>
                            <label className="block text-sm font-bold font-heading uppercase tracking-wider text-gray-300 mb-2">
                                Observações Finais
                            </label>
                            <textarea
                                name="notes"
                                value={formData.notes}
                                onChange={handleChange}
                                rows={3}
                                className="w-full px-4 py-3 bg-black border border-brand-red/20 text-white rounded-xl focus:ring-2 focus:ring-brand-orange focus:border-brand-orange outline-none transition-all placeholder:text-gray-600 resize-none"
                                placeholder="Algo importante para a edição? Momento de nocaute, detalhe que queira focar, etc."
                            />
                        </div>
                    </form>
                </div>

                <div className="p-6 border-t border-brand-red/20 flex flex-col sm:flex-row justify-end gap-3 bg-black/50">
                    <button
                        type="button"
                        onClick={onClose}
                        className="px-6 py-3 border border-gray-700 text-gray-400 rounded-xl font-bold hover:bg-gray-900 transition-colors uppercase tracking-wider text-sm"
                        disabled={isSubmitting}
                    >
                        Cancelar
                    </button>
                    <button
                        type="submit"
                        form="production-form"
                        disabled={isSubmitting}
                        className="px-8 py-3 bg-gradient-to-r from-brand-red to-brand-orange text-white rounded-xl font-black font-heading uppercase tracking-widest text-sm hover:shadow-[0_0_15px_rgba(220,38,38,0.4)] transition-all flex items-center justify-center gap-2 min-w-[180px] disabled:opacity-75 disabled:cursor-not-allowed"
                    >
                        {isSubmitting ? (
                            <>
                                <Loader2 className="w-4 h-4 animate-spin" />
                                Enviando...
                            </>
                        ) : (
                            'Enviar Informações'
                        )}
                    </button>
                </div>
            </div>
        </div>
    );
}

import React, { useState } from 'react';
import { supabase } from '../../lib/supabase';
import { X, Lock, User, Mail, Phone, Loader2 } from 'lucide-react';

interface LeadCaptureModalProps {
    isOpen: boolean;
    onClose: () => void;
    onSuccess: () => void;
}

export function LeadCaptureModal({ isOpen, onClose, onSuccess }: LeadCaptureModalProps) {
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);

    const [formData, setFormData] = useState({
        fullName: '',
        email: '',
        whatsapp: '',
        password: '' // Required for Supabase Auth
    });

    if (!isOpen) return null;

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        setError(null);

        try {
            // 1. Sign Up user in Supabase Auth
            const { data: authData, error: authError } = await supabase.auth.signUp({
                email: formData.email,
                password: formData.password,
                options: {
                    data: {
                        full_name: formData.fullName,
                        whatsapp: formData.whatsapp,
                    }
                }
            });

            if (authError) {
                // If user already exists, try to sign in (simplified flow for MVP)
                // In a real app, we'd handle "User already exists" more gracefully or use a separate login form
                if (authError.message.includes('already registered')) {
                    const { error: signInError } = await supabase.auth.signInWithPassword({
                        email: formData.email,
                        password: formData.password
                    });

                    if (signInError) throw signInError;

                    // If sign in successful, proceed
                    onSuccess();
                    return;
                }
                throw authError;
            }

            // 2. Insert into profiles table is handled by triggers (if configured) or we can do it manually here if needed
            // For now, we assume public.profiles is populated via Supabase Auth hook or we insert it here if we didn't set up the trigger yet.
            // Based on our SQL migration, we have a profiles table but didn't explicitly create a trigger to auto-insert from auth.users.
            // Let's manually insert/upsert into profiles to be safe for this MVP.

            if (authData.user) {
                const { error: profileError } = await supabase
                    .from('profiles')
                    .upsert({
                        id: authData.user.id,
                        email: formData.email,
                        full_name: formData.fullName,
                        whatsapp: formData.whatsapp,
                    });

                if (profileError) {
                    console.error('Error updating profile:', profileError);
                    // Don't block the flow if profile update fails, auth is what matters for checkout
                }
            }

            onSuccess();
        } catch (err: any) {
            setError(err.message || 'Ocorreu um erro ao salvar seus dados.');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
            <div className="bg-white rounded-2xl shadow-xl w-full max-w-md overflow-hidden relative animate-fade-in">
                <button
                    onClick={onClose}
                    className="absolute top-4 right-4 text-gray-400 hover:text-gray-600 transition-colors"
                >
                    <X className="w-6 h-6" />
                </button>

                <div className="p-8">
                    <div className="text-center mb-6">
                        <div className="w-12 h-12 bg-blue-100 rounded-full flex items-center justify-center mx-auto mb-4">
                            <Lock className="w-6 h-6 text-blue-600" />
                        </div>
                        <h2 className="text-2xl font-bold text-gray-900">Identifique-se</h2>
                        <p className="text-gray-500 mt-2">
                            Para prosseguir com a compra segura, precisamos de alguns dados seus.
                        </p>
                    </div>

                    {error && (
                        <div className="mb-4 p-3 bg-red-50 text-red-700 text-sm rounded-lg border border-red-100">
                            {error}
                        </div>
                    )}

                    <form onSubmit={handleSubmit} className="space-y-4">
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">Nome Completo</label>
                            <div className="relative">
                                <User className="absolute left-3 top-3 h-5 w-5 text-gray-400" />
                                <input
                                    type="text"
                                    required
                                    className="w-full pl-10 pr-4 py-2.5 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
                                    placeholder="Seu nome"
                                    value={formData.fullName}
                                    onChange={(e) => setFormData({ ...formData, fullName: e.target.value })}
                                />
                            </div>
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">E-mail</label>
                            <div className="relative">
                                <Mail className="absolute left-3 top-3 h-5 w-5 text-gray-400" />
                                <input
                                    type="email"
                                    required
                                    className="w-full pl-10 pr-4 py-2.5 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
                                    placeholder="seu@email.com"
                                    value={formData.email}
                                    onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                                />
                            </div>
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">WhatsApp</label>
                            <div className="relative">
                                <Phone className="absolute left-3 top-3 h-5 w-5 text-gray-400" />
                                <input
                                    type="tel"
                                    required
                                    className="w-full pl-10 pr-4 py-2.5 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
                                    placeholder="(11) 99999-9999"
                                    value={formData.whatsapp}
                                    onChange={(e) => setFormData({ ...formData, whatsapp: e.target.value })}
                                />
                            </div>
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">Senha (para acesso futuro)</label>
                            <div className="relative">
                                <Lock className="absolute left-3 top-3 h-5 w-5 text-gray-400" />
                                <input
                                    type="password"
                                    required
                                    minLength={6}
                                    className="w-full pl-10 pr-4 py-2.5 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
                                    placeholder="******"
                                    value={formData.password}
                                    onChange={(e) => setFormData({ ...formData, password: e.target.value })}
                                />
                            </div>
                        </div>

                        <button
                            type="submit"
                            disabled={loading}
                            className="w-full py-3 bg-blue-600 text-white rounded-lg font-bold text-lg hover:bg-blue-700 transition-all shadow-md hover:shadow-lg disabled:opacity-70 disabled:cursor-not-allowed flex items-center justify-center gap-2"
                        >
                            {loading ? (
                                <>
                                    <Loader2 className="w-5 h-5 animate-spin" />
                                    Processando...
                                </>
                            ) : (
                                'Continuar para Pagamento'
                            )}
                        </button>
                    </form>

                    <p className="mt-4 text-xs text-center text-gray-400">
                        Seus dados estão seguros e serão utilizados apenas para processar sua compra e enviar o acesso ao vídeo.
                    </p>
                </div>
            </div>
        </div>
    );
}

import { useState, useEffect } from 'react';
import { Video, User, LogOut, HelpCircle } from 'lucide-react';
import { Link, useNavigate } from 'react-router-dom';
import { supabase } from '../../lib/supabase';

export function Navbar() {
    const navigate = useNavigate();
    const [user, setUser] = useState<any>(null);

    useEffect(() => {
        // Check active session
        supabase.auth.getSession().then(({ data: { session } }) => {
            setUser(session?.user ?? null);
        });

        // Listen for changes
        const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
            setUser(session?.user ?? null);
        });

        return () => subscription.unsubscribe();
    }, []);

    const handleLogout = async () => {
        await supabase.auth.signOut();
        navigate('/');
    };

    return (
        <nav className="bg-brand-dark border-b border-brand-red/20 sticky top-0 z-50">
            <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
                <div className="flex justify-between items-center h-16">
                    <Link to="/" className="flex items-center space-x-2">
                        <div className="p-2 bg-gradient-to-br from-brand-red to-brand-orange rounded-lg shadow-lg shadow-brand-red/20">
                            <Video className="w-6 h-6 text-white" />
                        </div>
                        <span className="text-2xl font-black font-heading tracking-wider uppercase italic text-white">FightVideos</span>
                    </Link>

                    <div className="flex items-center space-x-4">
                        {user ? (
                            <div className="flex items-center space-x-4">


                                <Link
                                    to="/ajuda"
                                    className="flex items-center text-gray-300 hover:text-brand-orange font-medium transition-colors"
                                >
                                    <HelpCircle className="w-5 h-5 mr-2" />
                                    Ajuda
                                </Link>

                                <Link
                                    to="/minha-conta"
                                    className="flex items-center text-gray-300 hover:text-brand-orange font-medium transition-colors"
                                >
                                    <User className="w-5 h-5 mr-2" />
                                    Minha Conta
                                </Link>

                                <button
                                    onClick={handleLogout}
                                    className="p-2 text-brand-red hover:bg-brand-red/10 rounded-lg transition-colors"
                                    title="Sair"
                                >
                                    <LogOut className="w-5 h-5" />
                                </button>
                            </div>
                        ) : (
                            <>
                                <Link to="/ajuda" className="text-gray-300 hover:text-white font-medium text-sm sm:text-base hidden sm:block transition-colors">
                                    Ajuda
                                </Link>
                                <Link to="/login" className="text-gray-300 hover:text-white font-medium text-sm sm:text-base transition-colors">
                                    Login
                                </Link>
                                <Link to="/signup" className="px-5 py-2.5 bg-gradient-to-r from-brand-red to-brand-orange text-white rounded-lg font-bold uppercase tracking-wider text-sm hover:shadow-lg hover:shadow-brand-red/30 transition-all font-heading">
                                    Cadastrar
                                </Link>
                            </>
                        )}
                    </div>
                </div>
            </div>
        </nav>
    );
}

