export function MyAccountPage() {
    const navigate = useNavigate();
    const [user, setUser] = useState<any>(null);
    const [myOrders, setMyOrders] = useState<Order[]>([]);
    const [loading, setLoading] = useState(true);

    // Modal state
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [selectedOrderItem, setSelectedOrderItem] = useState<OrderItem | null>(null);

    // Pix Modal state
    const [isPixModalOpen, setIsPixModalOpen] = useState(false);
    const [selectedPixOrder, setSelectedPixOrder] = useState<Order | null>(null);

    // Tab State
    const [activeTab, setActiveTab] = useState<'orders' | 'settings'>('orders');

    const [profile, setProfile] = useState({
        full_name: '',
        whatsapp: '',
        cpf: ''
    });
    const [savingProfile, setSavingProfile] = useState(false);
    const [email, setEmail] = useState('');
    const [savingEmail, setSavingEmail] = useState(false);

    // Password Update State
    const [password, setPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');
    const [savingPassword, setSavingPassword] = useState(false);

    useEffect(() => {
        checkAuth();
    }, []);

    const checkAuth = async () => {
        const { data: { user } } = await supabase.auth.getUser();
        if (!user) {
            navigate('/');
            return;
        }
        setUser(user);
        loadData(user.id);
    };

    const loadData = async (userId: string) => {
        setLoading(true);
        try {
            const [ordersData, profileRes] = await Promise.all([
                VideoService.getMyOrders(userId),
                supabase.from('profiles').select('*').eq('id', userId).single()
            ]);

            setMyOrders(ordersData);

            if (profileRes.data) {
                setProfile({
                    full_name: profileRes.data.full_name || '',
                    whatsapp: profileRes.data.whatsapp || '',
                    cpf: profileRes.data.cpf || ''
                });
                setEmail(user.email || ''); // get email from user object
            }
        } catch (error) {
            console.error("Error loading account data:", error);
        }
        setLoading(false);
    };

    const handleSaveProfile = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!user) return;
        setSavingProfile(true);

        try {
            const { error } = await supabase.from('profiles').update({
                full_name: profile.full_name,
                whatsapp: profile.whatsapp,
                cpf: profile.cpf
            }).eq('id', user.id);

            if (error) throw error;

            // Also update auth metadata to keep it consistent
            await supabase.auth.updateUser({
                data: {
                    full_name: profile.full_name,
                    whatsapp: profile.whatsapp,
                    cpf: profile.cpf
                }
            });

            alert('Perfil atualizado com sucesso!');
        } catch (error: any) {
            console.error('Error saving profile:', error);
            alert('Erro ao salvar perfil: ' + error.message);
        } finally {
            setSavingProfile(false);
        }
    };

    const handleSaveEmail = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!user) return;
        setSavingEmail(true);

        try {
            const { error: authError } = await supabase.auth.updateUser({
                email: email
            });

            if (authError) {
                if (authError.message.includes('already registered')) {
                    throw new Error('Este email já está sendo usado por outra conta.');
                }
                throw authError;
            }

            alert('Email de login atualizado com sucesso! (Verifique sua caixa de entrada no novo email para confirmar).');
        } catch (error: any) {
            console.error('Error saving email:', error);
            alert('Erro ao salvar email: ' + error.message);
        } finally {
            setSavingEmail(false);
        }
    };

    const handleSavePassword = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!user) return;

        if (password !== confirmPassword) {
            alert('As senhas não coincidem.');
            return;
        }

        if (password.length < 6) {
            alert('A senha deve ter pelo menos 6 caracteres.');
            return;
        }

        setSavingPassword(true);

        try {
            const { error } = await supabase.auth.updateUser({
                password: password
            });

            if (error) throw error;

            alert('Senha atualizada com sucesso!');
            setPassword('');
            setConfirmPassword('');
        } catch (error: any) {
            console.error('Error saving password:', error);
            alert('Erro ao atualizar senha: ' + error.message);
        } finally {
            setSavingPassword(false);
        }
