    const [loading, setLoading] = useState(true);
    const [isAuthModalOpen, setIsAuthModalOpen] = useState(false);

    useEffect(() => {
        if (slug) {
            loadVideo(slug);
        }
    }, [slug]);

    const loadVideo = async (videoSlug: string) => {
        setLoading(true);
        const data = await VideoService.getBySlug(videoSlug);
        setVideo(data);
        setLoading(false);
    };

