import { useEffect, useState } from 'react';
import { type Event } from '../../types';
import { EventService } from '../../services/event.service';
import { Plus, Trash2, Calendar, MapPin, Loader2, Edit, FolderOpen, Image as ImageIcon } from 'lucide-react';
import { supabase } from '../../lib/supabase';
import { compressImageToWebp } from '../../utils/imageUtils';

export function AdminEventsPage() {
    const [events, setEvents] = useState<Event[]>([]);
    const [loading, setLoading] = useState(true);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [newEvent, setNewEvent] = useState<Partial<Event>>({
        title: '',
        location: '',
        fight_date: new Date().toISOString().split('T')[0],
        banner_url: '',
        drive_link: '',
        is_active: true
    });
    const [editingId, setEditingId] = useState<string | null>(null);
    const [selectedImageFile, setSelectedImageFile] = useState<File | null>(null);
    const [imagePreview, setImagePreview] = useState<string | null>(null);

    useEffect(() => {
        loadEvents();
    }, []);

    const loadEvents = async () => {
        setLoading(true);
        const data = await EventService.getAll();
        setEvents(data);
        setLoading(false);
    };

    const handleSaveEvent = async (e: React.FormEvent) => {
        e.preventDefault();
        try {
            const slug = newEvent.title?.toLowerCase().replace(/ /g, '-').replace(/[^\w-]+/g, '');
            const eventData = { ...newEvent, slug };

            if (selectedImageFile) {
                const webpFile = await compressImageToWebp(selectedImageFile);

                // Upload to Supabase Storage
                const fileName = `${Date.now()}_${slug || 'event'}.webp`;
                const { error: uploadError } = await supabase.storage
                    .from('banners')
                    .upload(fileName, webpFile, {
                        cacheControl: '3600',
                        upsert: false
                    });

                if (uploadError) {
                    console.error('Error uploading image:', uploadError);
                    alert('Erro ao fazer upload da imagem. O evento não foi salvo.');
                    return;
                }

                // Get Public URL
                const { data: publicUrlData } = supabase.storage
                    .from('banners')
                    .getPublicUrl(fileName);

                eventData.banner_url = publicUrlData.publicUrl;
            }

            let success = false;
            if (editingId) {
                success = await EventService.update(editingId, eventData);
                if (success) alert('Evento atualizado com sucesso!');
            } else {
                success = await EventService.create(eventData);
                if (success) alert('Evento criado com sucesso!');
            }

            if (success) {
                closeModal();
                loadEvents();
            } else {
                alert('Erro ao salvar evento');
            }
        } catch (error) {
            console.error('Error saving event:', error);
            alert('Erro ao salvar evento');
        }
    };

    const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            setSelectedImageFile(file);
            const objectUrl = URL.createObjectURL(file);
            setImagePreview(objectUrl);
        }
    };

    const handleEditClick = (event: Event) => {
        setNewEvent({
            title: event.title,
            location: event.location || '',
            fight_date: event.fight_date,
            banner_url: event.banner_url || '',
            drive_link: event.drive_link || '',
            is_active: event.is_active
        });
        setEditingId(event.id);
        setSelectedImageFile(null);
        setImagePreview(event.banner_url || null);
        setIsModalOpen(true);
    };

    const closeModal = () => {
        setIsModalOpen(false);
        setEditingId(null);
        setNewEvent({
            title: '',
            location: '',
            fight_date: new Date().toISOString().split('T')[0],
            banner_url: '',
            drive_link: '',
            is_active: true
        });
        setSelectedImageFile(null);
        setImagePreview(null);
    };

    const handleDeleteEvent = async (id: string, title: string) => {
        if (!confirm(`Tem certeza que deseja excluir o evento "${title}"?`)) return;

        const { error } = await supabase.from('events').delete().eq('id', id);
        if (error) {
            alert('Erro ao excluir evento');
        } else {
            loadEvents();
        }
    };

    return (
        <div>
            <div className="flex justify-between items-center mb-8">
                <h1 className="text-2xl font-bold text-gray-900">Gerenciar Eventos</h1>
                <button
                    onClick={() => {
                        closeModal();
                        setIsModalOpen(true);
                    }}
                    className="flex items-center px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors"
                >
                    <Plus className="w-5 h-5 mr-2" />
                    Novo Evento
                </button>
            </div>

            <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
                <table className="w-full text-left border-collapse">
                    <thead>
                        <tr className="bg-gray-50 border-b border-gray-100">
                            <th className="p-4 font-semibold text-gray-600 text-sm">Evento</th>
                            <th className="p-4 font-semibold text-gray-600 text-sm">Data</th>
                            <th className="p-4 font-semibold text-gray-600 text-sm">Local</th>
                            <th className="p-4 font-semibold text-gray-600 text-sm">Status</th>
                            <th className="p-4 font-semibold text-gray-600 text-sm text-right">Ações</th>
                        </tr>
                    </thead>
                    <tbody>
                        {loading ? (
                            <tr>
                                <td colSpan={5} className="p-8 text-center text-gray-500">
                                    <Loader2 className="w-6 h-6 animate-spin mx-auto mb-2" />
                                    Carregando eventos...
                                </td>
                            </tr>
                        ) : events.length === 0 ? (
                            <tr>
                                <td colSpan={5} className="p-8 text-center text-gray-500">Nenhum evento encontrado.</td>
                            </tr>
                        ) : (
                            events.map(event => (
                                <tr key={event.id} className="border-b border-gray-50 hover:bg-gray-50/50">
                                    <td className="p-4">
                                        <div className="flex items-center">
                                            {event.banner_url && (
                                                <img src={event.banner_url} alt="" loading="lazy" className="w-10 h-10 rounded object-cover mr-3" />
                                            )}
                                            <div>
                                                <div className="font-medium text-gray-900">{event.title}</div>
                                                <div className="text-xs text-gray-400">ID: {event.id.substring(0, 8)}...</div>
                                            </div>
                                        </div>
                                    </td>
                                    <td className="p-4 text-gray-600">
                                        <div className="flex items-center">
                                            <Calendar className="w-4 h-4 mr-2 text-gray-400" />
                                            {new Date(event.fight_date + 'T12:00:00').toLocaleDateString()}
                                        </div>
                                    </td>
                                    <td className="p-4 text-gray-600">
                                        <div className="flex items-center">
                                            <MapPin className="w-4 h-4 mr-2 text-gray-400" />
                                            {event.location || '-'}
                                        </div>
                                    </td>
                                    <td className="p-4">
                                        <span className={`px-2 py-1 rounded-full text-xs font-semibold ${event.is_active ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
                                            {event.is_active ? 'Ativo' : 'Inativo'}
                                        </span>
                                    </td>
                                    <td className="p-4 text-right">
                                        <div className="flex justify-end gap-2 items-center">
                                            {event.drive_link && (
                                                <a
                                                    href={event.drive_link}
                                                    target="_blank"
                                                    rel="noopener noreferrer"
                                                    className="p-2 text-gray-400 hover:text-green-600 hover:bg-green-50 rounded-lg transition-colors"
                                                    title="Acessar Pasta no Drive"
                                                >
                                                    <FolderOpen className="w-4 h-4" />
                                                </a>
                                            )}
                                            <a
                                                href={`/admin/events/${event.id}/videos`}
                                                className="px-3 py-1.5 text-sm bg-blue-50 text-blue-700 hover:bg-blue-100 rounded-lg transition-colors font-medium flex items-center"
                                                title="Gerenciar Card de Lutas"
                                            >
                                                Card de Lutas
                                            </a>
                                            <button
                                                onClick={() => handleEditClick(event)}
                                                className="p-2 text-gray-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors"
                                                title="Editar"
                                            >
                                                <Edit className="w-4 h-4" />
                                            </button>
                                            <button
                                                onClick={() => handleDeleteEvent(event.id, event.title)}
                                                className="p-2 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors"
                                            >
                                                <Trash2 className="w-4 h-4" />
                                            </button>
                                        </div>
                                    </td>
                                </tr>
                            ))
                        )}
                    </tbody>
                </table>
            </div>

            {isModalOpen && (
                <div className="fixed inset-0 bg-black/50 flex items-center justify-center p-4 z-50">
                    <div className="bg-white rounded-xl p-6 w-full max-w-lg">
                        <h2 className="text-xl font-bold mb-4">{editingId ? 'Editar Evento' : 'Novo Evento'}</h2>
                        <form onSubmit={handleSaveEvent} className="space-y-4">
                            <div>
                                <label className="block text-sm font-medium text-gray-700">Título do Evento</label>
                                <input
                                    type="text"
                                    className="w-full mt-1 p-2 border rounded-lg"
                                    placeholder="Ex: High Nocaute 5"
                                    value={newEvent.title}
                                    onChange={e => setNewEvent({ ...newEvent, title: e.target.value })}
                                    required
                                />
                            </div>

                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-sm font-medium text-gray-700">Data</label>
                                    <input
                                        type="date"
                                        className="w-full mt-1 p-2 border rounded-lg"
                                        value={newEvent.fight_date}
                                        onChange={e => setNewEvent({ ...newEvent, fight_date: e.target.value })}
                                        required
                                    />
                                </div>
                                <div>
                                    <label className="block text-sm font-medium text-gray-700">Local</label>
                                    <input
                                        type="text"
                                        className="w-full mt-1 p-2 border rounded-lg"
                                        placeholder="Ex: Ginásio X"
                                        value={newEvent.location}
                                        onChange={e => setNewEvent({ ...newEvent, location: e.target.value })}
                                    />
                                </div>
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Banner do Evento</label>

                                <div className="border border-gray-300 rounded-lg p-4 bg-gray-50 flex flex-col items-center">
                                    {(imagePreview || newEvent.banner_url) && (
                                        <div className="mb-4 w-full">
                                            <img
                                                src={imagePreview || newEvent.banner_url}
                                                alt="Preview"
                                                className="w-full h-32 object-cover rounded-md border border-gray-200"
                                            />
                                        </div>
                                    )}
                                    <label className="flex items-center justify-center w-full px-4 py-2 bg-white border border-gray-300 rounded-lg cursor-pointer hover:bg-gray-50 transition-colors">
                                        <ImageIcon className="w-5 h-5 mr-2 text-gray-500" />
                                        <span className="text-gray-700 text-sm">{imagePreview ? 'Trocar Imagem' : 'Selecionar Imagem do PC'}</span>
                                        <input
                                            type="file"
                                            accept="image/*"
                                            className="hidden"
                                            onChange={handleImageChange}
                                        />
                                    </label>
                                    <p className="text-xs text-gray-500 mt-2 text-center">
                                        A imagem será otimizada (WebP) magicamente antes do envio.
                                    </p>
                                </div>
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-gray-700">Link da Pasta no Drive (Somente Admin)</label>
                                <input
                                    type="url"
                                    className="w-full mt-1 p-2 border rounded-lg"
                                    placeholder="https://drive.google.com/..."
                                    value={newEvent.drive_link}
                                    onChange={e => setNewEvent({ ...newEvent, drive_link: e.target.value })}
                                />
                                <p className="text-xs text-gray-500 mt-1">
                                    Este link não será visto pelos clientes. É um atalho para facilitar o acesso da produção aos vídeos brutos.
                                </p>
                            </div>

                            <div className="flex justify-end gap-3 mt-6">
                                <button
                                    type="button"
                                    onClick={closeModal}
                                    className="px-4 py-2 text-gray-600 hover:bg-gray-100 rounded-lg"
                                >
                                    Cancelar
                                </button>
                                <button
                                    type="submit"
                                    className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700"
                                >
                                    Salvar Evento
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
}

import { useEffect, useState } from 'react';
import { supabase } from '../../lib/supabase';
import { Package, Search, Calendar, CheckCircle, Clock, XCircle, Download } from 'lucide-react';
import { format } from 'date-fns';
import { ptBR } from 'date-fns/locale';

interface OrderDetail {
    id: string;
    total_amount: number;
    status: string;
    payment_method: string;
    created_at: string;
    profiles: {
        full_name: string;
        email: string;
        cpf: string;
        whatsapp: string;
    };
    order_items: {
        access_level: string;
        videos: {
            title: string;
            event_name: string;
        };
    }[];
}

export function AdminOrdersPage() {
    const [orders, setOrders] = useState<OrderDetail[]>([]);
    const [loading, setLoading] = useState(true);
    const [statusFilter, setStatusFilter] = useState<string>('all');
    const [searchTerm, setSearchTerm] = useState('');

    useEffect(() => {
        loadOrders();
    }, []);

    const loadOrders = async () => {
        setLoading(true);
        try {
            const { data, error } = await supabase
                .from('orders')
                .select(`
                    id, 
                    total_amount, 
                    status, 
                    payment_method, 
                    created_at,
                    profiles (full_name, email, cpf, whatsapp),
                    order_items (
                        access_level,
                        videos (title, event_name)
                    )
                `)
                .order('created_at', { ascending: false });

            if (error) throw error;
            setOrders((data as any[]) || []);
        } catch (error) {
            console.error('Erro ao carregar pedidos:', error);
        } finally {
            setLoading(false);
        }
    };

    const getStatusStyle = (status: string) => {
        switch (status) {
            case 'paid': return 'bg-green-100 text-green-700 border-green-200';
            case 'pending': return 'bg-yellow-100 text-yellow-700 border-yellow-200';
            case 'canceled':
            case 'failed': return 'bg-red-100 text-red-700 border-red-200';
            default: return 'bg-gray-100 text-gray-700 border-gray-200';
        }
    };

    const getStatusLabel = (status: string) => {
        switch (status) {
            case 'paid': return 'Aprovado';
            case 'pending': return 'Pendente';
            case 'canceled': return 'Cancelado';
            case 'failed': return 'Falhou';
            default: return status;
        }
    };

    const filteredOrders = orders.filter(order => {
        const matchesStatus = statusFilter === 'all' || order.status === statusFilter;

        const searchLower = searchTerm.toLowerCase();
        const matchesSearch =
            order.id.toLowerCase().includes(searchLower) ||
            order.profiles?.full_name?.toLowerCase().includes(searchLower) ||
            order.profiles?.email?.toLowerCase().includes(searchLower) ||
            order.profiles?.cpf?.includes(searchLower);

        return matchesStatus && matchesSearch;
    });

    const exportToCsv = () => {
        if (filteredOrders.length === 0) return;

        const headers = ['ID Pedido', 'Data', 'Cliente', 'Email', 'CPF', 'WhatsApp', 'Vídeo', 'Acesso', 'Pagamento', 'Status', 'Valor'];

        const csvData = filteredOrders.map(order => {
            const date = new Date(order.created_at).toLocaleDateString('pt-BR');
            const itemName = order.order_items?.[0]?.videos?.title || 'N/A';
            const access = order.order_items?.[0]?.access_level === 'full_access' ? 'Completo' : 'Highlight';

            return [
                order.id,
                date,
                order.profiles?.full_name || '',
                order.profiles?.email || '',
                order.profiles?.cpf || '',
                order.profiles?.whatsapp || '',
                itemName,
                access,
                order.payment_method === 'pix' ? 'Pix' : 'Cartão',
                getStatusLabel(order.status),
                order.total_amount
            ].join(',');
        });

        const csvString = [headers.join(','), ...csvData].join('\n');
        const blob = new Blob([csvString], { type: 'text/csv;charset=utf-8;' });
        const link = document.createElement('a');
        link.href = URL.createObjectURL(blob);
        link.download = `pedidos_${format(new Date(), 'dd-MM-yyyy')}.csv`;
        link.click();
    };

    return (
        <div className="space-y-6">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div>
                    <h1 className="text-2xl font-bold text-gray-900 flex items-center gap-2">
                        <Package className="w-6 h-6 text-blue-600" />
                        Gerenciamento de Pedidos
                    </h1>
                    <p className="text-gray-500 text-sm mt-1">Veja todos os pedidos, status de pagamentos e dados dos clientes.</p>
                </div>

                <button
                    onClick={exportToCsv}
                    className="flex items-center gap-2 px-4 py-2 bg-slate-800 text-white rounded-lg hover:bg-slate-700 transition"
                >
                    <Download className="w-4 h-4" />
                    Exportar
                </button>
            </div>

            <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
                <div className="p-4 border-b border-gray-100 flex flex-col md:flex-row gap-4 justify-between bg-gray-50/50">
                    <div className="flex gap-2 p-1 bg-gray-100 rounded-lg self-start">
                        <button
                            onClick={() => setStatusFilter('all')}
                            className={`px-4 py-1.5 rounded-md text-sm font-medium transition ${statusFilter === 'all' ? 'bg-white shadow text-gray-900' : 'text-gray-600 hover:text-gray-900'}`}
                        >
                            Todos
                        </button>
                        <button
                            onClick={() => setStatusFilter('paid')}
                            className={`px-4 py-1.5 rounded-md text-sm font-medium transition flex items-center gap-1 ${statusFilter === 'paid' ? 'bg-white shadow text-green-700' : 'text-gray-600 hover:text-gray-900'}`}
                        >
                            <CheckCircle className="w-4 h-4" /> Aprovados
                        </button>
                        <button
                            onClick={() => setStatusFilter('pending')}
                            className={`px-4 py-1.5 rounded-md text-sm font-medium transition flex items-center gap-1 ${statusFilter === 'pending' ? 'bg-white shadow text-yellow-700' : 'text-gray-600 hover:text-gray-900'}`}
                        >
                            <Clock className="w-4 h-4" /> Pendentes
                        </button>
                        <button
                            onClick={() => setStatusFilter('failed')}
                            className={`px-4 py-1.5 rounded-md text-sm font-medium transition flex items-center gap-1 ${statusFilter === 'failed' ? 'bg-white shadow text-red-700' : 'text-gray-600 hover:text-gray-900'}`}
                        >
                            <XCircle className="w-4 h-4" /> Falhos
                        </button>
                    </div>

                    <div className="relative relative max-w-md w-full">
                        <Search className="w-5 h-5 text-gray-400 absolute left-3 top-1/2 -translate-y-1/2" />
                        <input
                            type="text"
                            placeholder="Buscar por nome, email, CPF ou ID do pedido..."
                            className="w-full pl-10 pr-4 py-2 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                        />
                    </div>
                </div>

                <div className="overflow-x-auto">
                    <table className="w-full text-left border-collapse min-w-[1000px]">
                        <thead>
                            <tr className="bg-gray-50 border-b border-gray-100 uppercase text-xs font-semibold text-gray-500 tracking-wider">
                                <th className="p-4 w-24">ID</th>
                                <th className="p-4">Cliente</th>
                                <th className="p-4">Item Comprado</th>
                                <th className="p-4">Data</th>
                                <th className="p-4">Pagamento</th>
                                <th className="p-4 text-right">Valor</th>
                                <th className="p-4 text-center">Status</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-50">
                            {loading ? (
                                <tr><td colSpan={7} className="p-8 text-center text-gray-500">Carregando pedidos...</td></tr>
                            ) : filteredOrders.length === 0 ? (
                                <tr><td colSpan={7} className="p-8 text-center text-gray-500">Nenhum pedido encontrado.</td></tr>
                            ) : (
                                filteredOrders.map(order => {
                                    const firstItem = order.order_items?.[0];
                                    const isFullAccess = firstItem?.access_level === 'full_access';

                                    return (
                                        <tr key={order.id} className="hover:bg-gray-50/50 transition-colors">
                                            <td className="p-4 text-xs font-mono text-gray-400">
                                                {order.id.split('-')[0]}
                                            </td>
                                            <td className="p-4 text-sm">
                                                <div className="font-medium text-gray-900">{order.profiles?.full_name || 'Usuário Deletado'}</div>
                                                <div className="text-gray-500 text-xs">{order.profiles?.email}</div>
                                                <div className="text-gray-400 text-xs mt-1">CPF: {order.profiles?.cpf || 'Não informado'}</div>
                                            </td>
                                            <td className="p-4">
                                                {firstItem ? (
                                                    <div>
                                                        <div className="font-medium text-gray-800 text-sm line-clamp-1" title={firstItem.videos.title}>
                                                            {firstItem.videos.title}
                                                        </div>
                                                        <div className="flex items-center gap-2 mt-1">
                                                            <span className="text-xs text-gray-500">{firstItem.videos.event_name}</span>
                                                            <span className={`text-[10px] px-2 py-0.5 rounded-full font-bold uppercase tracking-wide ${isFullAccess ? 'bg-purple-100 text-purple-700' : 'bg-blue-100 text-blue-700'}`}>
                                                                {isFullAccess ? 'Luta Completa' : 'Highlight'}
                                                            </span>
                                                        </div>
                                                    </div>
                                                ) : <span className="text-gray-400 text-sm">Sem item vinculado</span>}
                                            </td>
                                            <td className="p-4 text-sm text-gray-600">
                                                <div className="flex items-center gap-2">
                                                    <Calendar className="w-4 h-4 text-gray-400" />
                                                    {format(new Date(order.created_at), "dd MMM yy, HH:mm", { locale: ptBR })}
                                                </div>
                                            </td>
                                            <td className="p-4">
                                                <span className={`px-2 py-1 bg-gray-100 rounded text-xs font-semibold ${order.payment_method === 'pix' ? 'text-green-700' : 'text-blue-700'}`}>
                                                    {order.payment_method === 'pix' ? 'PIX' : 'CARTÃO'}
                                                </span>
                                            </td>
                                            <td className="p-4 text-right font-medium text-gray-900">
                                                {new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(order.total_amount)}
                                            </td>
                                            <td className="p-4 text-center">
                                                <span className={`inline-flex items-center px-2.5 py-1 rounded-full text-xs font-medium border ${getStatusStyle(order.status)}`}>
                                                    {getStatusLabel(order.status)}
                                                </span>
                                            </td>
                                        </tr>
                                    );
                                })
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
}

import { useEffect, useState } from 'react';
import { supabase } from '../../lib/supabase';
import { Loader2, Video, CheckCircle, ExternalLink, RefreshCw, Send } from 'lucide-react';

export function AdminProductionPage() {
    const [loading, setLoading] = useState(true);
    const [productions, setProductions] = useState<any[]>([]);
    const [eventsMap, setEventsMap] = useState<Record<string, string>>({});
    const [updatingId, setUpdatingId] = useState<string | null>(null);
    const [deliveryUrls, setDeliveryUrls] = useState<{ [key: string]: string }>({});
    const [expandedEvents, setExpandedEvents] = useState<Record<string, boolean>>({});
    const [editingDelivered, setEditingDelivered] = useState<Record<string, boolean>>({});

    useEffect(() => {
        loadProductions();
    }, []);

    const loadProductions = async () => {
        setLoading(true);

        const [eventsRes, prodRes] = await Promise.all([
            supabase.from('events').select('id, title'),
            supabase
                .from('order_items')
                .select(`
                    *,
                    videos ( title, event_id, event_name ),
                    orders ( id, created_at, status )
                `)
                .in('production_status', ['in_production', 'delivered'])
                .order('id', { ascending: false })
        ]);

        if (eventsRes.data) {
            const map: Record<string, string> = {};
            eventsRes.data.forEach(e => map[e.id] = e.title);
            setEventsMap(map);
        }

        if (!prodRes.error && prodRes.data) {
            const sorted = prodRes.data.sort((a, b) => {
                const dateA = new Date(a.orders?.created_at || 0).getTime();
                const dateB = new Date(b.orders?.created_at || 0).getTime();
                return dateB - dateA;
            });
            setProductions(sorted);

            // Pre-populate delivery URLs for items that are already delivered
            const initialUrls: Record<string, string> = {};
            sorted.forEach(item => {
                if (item.delivered_video_url) {
                    initialUrls[item.id] = item.delivered_video_url;
                }
            });
            setDeliveryUrls(initialUrls);
        } else {
            console.error("Error fetching productions:", prodRes.error);
        }
        setLoading(false);
    };

    const toggleEvent = (eventId: string) => {
        setExpandedEvents(prev => ({
            ...prev,
            [eventId]: !prev[eventId]
        }));
    };

    const handleDeliver = async (itemId: string) => {
        let url = deliveryUrls[itemId];
        if (!url || !url.trim()) {
            alert('Por favor, insira o link do vídeo finalizado.');
            return;
        }

        url = url.trim();
        if (!url.startsWith('http://') && !url.startsWith('https://')) {
            url = `https://${url}`;
        }

        setUpdatingId(itemId);
        try {
            const { error } = await supabase
                .from('order_items')
                .update({
                    production_status: 'delivered',
                    delivered_video_url: url
                })
                .eq('id', itemId);

            if (error) throw error;

            alert('Vídeo entregue com sucesso! O cliente já pode acessar.');
            await loadProductions(); // Reload list
        } catch (error: any) {
            console.error('Error delivering video:', error);
            alert('Erro ao entregar o vídeo: ' + error.message);
        } finally {
            setUpdatingId(null);
        }
    };

    const handleUrlChange = (itemId: string, value: string) => {
        setDeliveryUrls(prev => ({ ...prev, [itemId]: value }));
    };

    if (loading) {
        return (
            <div className="flex h-64 items-center justify-center">
                <Loader2 className="w-8 h-8 animate-spin text-blue-600" />
            </div>
        );
    }

    interface GroupedEvent {
        eventId: string;
        eventTitle: string;
        pending: any[];
        delivered: any[];
    }

    const groupedProductions: GroupedEvent[] = Object.values(
        productions.reduce((acc, item) => {
            const eventId = item.videos?.event_id || 'unknown';
            const eventTitle = eventsMap[eventId] || item.videos?.event_name || 'Evento Desconhecido';

            if (!acc[eventId]) {
                acc[eventId] = { eventId, eventTitle, pending: [], delivered: [] };
            }

            if (item.production_status === 'in_production') acc[eventId].pending.push(item);
            else if (item.production_status === 'delivered') acc[eventId].delivered.push(item);

            return acc;
        }, {} as Record<string, GroupedEvent>)
    );

    return (
        <div className="max-w-6xl mx-auto">
            <div className="flex justify-between items-center mb-8">
                <div>
                    <h1 className="text-3xl font-bold text-gray-900">Fila de Produção</h1>
                    <p className="text-gray-500 mt-1">Gerencie os pedidos de highlight separados por evento.</p>
                </div>
                <button
                    onClick={loadProductions}
                    className="flex items-center gap-2 px-4 py-2 bg-white border border-gray-300 rounded-lg text-gray-700 hover:bg-gray-50 transition-colors"
                >
                    <RefreshCw className="w-4 h-4" />
                    Atualizar Fila
                </button>
            </div>

            {groupedProductions.length === 0 ? (
                <div className="bg-white p-8 rounded-2xl border border-gray-200 text-center text-gray-500">
                    Nenhum vídeo na fila de edição ou entregue no momento.
                </div>
            ) : (
                <div className="space-y-6">
                    {groupedProductions.map(group => {
                        const isExpanded = expandedEvents[group.eventId];
                        const total = group.pending.length + group.delivered.length;

                        return (
                            <div key={group.eventId} className="bg-white rounded-2xl border border-gray-200 shadow-sm overflow-hidden transition-all">
                                {/* Accordion Header */}
                                <div
                                    className="p-6 cursor-pointer hover:bg-gray-50 flex items-center justify-between"
                                    onClick={() => toggleEvent(group.eventId)}
                                >
                                    <div className="flex items-center gap-4">
                                        <div className="p-3 bg-blue-50 text-blue-600 rounded-xl">
                                            <Video className="w-6 h-6" />
                                        </div>
                                        <div>
                                            <h2 className="text-xl font-bold text-gray-900">{group.eventTitle}</h2>
                                            <p className="text-sm text-gray-500">Total de pedidos: {total}</p>
                                        </div>
                                    </div>
                                    <div className="flex gap-3">
                                        {group.pending.length > 0 && (
                                            <span className="px-3 py-1 bg-yellow-100 text-yellow-800 rounded-full text-sm font-medium">
                                                {group.pending.length} Pendentes
                                            </span>
                                        )}
                                        {group.delivered.length > 0 && (
                                            <span className="px-3 py-1 bg-green-100 text-green-800 rounded-full text-sm font-medium">
                                                {group.delivered.length} Entregues
                                            </span>
                                        )}
                                    </div>
                                </div>

                                {/* Accordion Body */}
                                {isExpanded && (
                                    <div className="border-t border-gray-100 bg-gray-50 p-6 space-y-8">
                                        {group.pending.length > 0 && (
                                            <div>
                                                <h3 className="text-lg font-bold text-gray-800 mb-4">Aguardando Edição</h3>
                                                <div className="space-y-6">
                                                    {group.pending.map(item => {
                                                        const formData = item.production_form_data || {};
                                                        return (
                                                            <div key={item.id} className="bg-white p-6 rounded-2xl shadow-sm border border-gray-200">
                                                                <div className="flex justify-between items-start mb-6">
                                                                    <div>
                                                                        <h4 className="text-lg font-bold text-gray-900">
                                                                            Highlight: {formData.fighterName || 'Atleta Não Informado'}
                                                                        </h4>
                                                                        <p className="text-sm text-gray-500 mt-1">
                                                                            Luta: {item.videos?.title} • Pedido: {item.order_id?.substring(0, 8).toUpperCase()}
                                                                        </p>
                                                                    </div>
                                                                    <div className="text-right text-sm text-gray-500">
                                                                        Data do Pedido: <br />
                                                                        {item.orders?.created_at ? new Date(item.orders.created_at).toLocaleDateString('pt-BR') : 'N/A'}
                                                                    </div>
                                                                </div>

                                                                <div className="bg-gray-50 p-4 rounded-xl mb-6 grid grid-cols-1 md:grid-cols-3 gap-6 text-sm border border-gray-100">
                                                                    <div>
                                                                        <p className="text-gray-500 mb-1">Contato</p>
                                                                        <p className="font-medium text-gray-900">{formData.email}</p>
                                                                        <p className="font-medium text-gray-900">{formData.contact1}</p>
                                                                        {formData.instagram && <p className="text-blue-600">{formData.instagram}</p>}
                                                                    </div>
                                                                    <div>
                                                                        <p className="text-gray-500 mb-1">Dados da Luta</p>
                                                                        <p className="font-medium text-gray-900">Rounds: {formData.roundsCount}</p>
                                                                        <p className="font-medium text-gray-900">Corner: {formData.cornerColor}</p>
                                                                        <p className="font-medium text-gray-900">Equipe: {formData.team}</p>
                                                                    </div>
                                                                    <div>
                                                                        <p className="text-gray-500 mb-1">Música</p>
                                                                        {formData.musicLink ? (
                                                                            <a href={formData.musicLink} target="_blank" rel="noopener noreferrer" className="text-red-600 hover:underline flex items-center font-medium">
                                                                                Abrir Link YouTube
                                                                            </a>
