import { useState, useEffect } from 'react';
import { supabase } from '../../lib/supabase';
import { useNavigate } from 'react-router-dom';
import { Lock, Loader2, CheckCircle } from 'lucide-react';

export function UpdatePasswordPage() {
    const navigate = useNavigate();
    const [loading, setLoading] = useState(false);
    const [password, setPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');
    const [error, setError] = useState<string | null>(null);
    const [success, setSuccess] = useState(false);

    useEffect(() => {
        // Check if user has an active session indicating they came from a password reset link
        const checkSession = async () => {
            const { data: { session } } = await supabase.auth.getSession();
            if (!session) {
                navigate('/login');
            }
        };

        // Supabase uses the hash fragment to pass tokens. getSession() usually handles this for us on load.
        checkSession();

        const { data: { subscription } } = supabase.auth.onAuthStateChange((event) => {
            if (event === 'PASSWORD_RECOVERY') {
                // User is ready to reset password
                // This event fires when clicking the recovery link if hash contains access_token & type=recovery
            }
        });

        return () => subscription.unsubscribe();
    }, [navigate]);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();

        if (password !== confirmPassword) {
            setError('As senhas não coincidem.');
            return;
        }

        if (password.length < 6) {
            setError('A senha deve ter pelo menos 6 caracteres.');
            return;
        }

        setLoading(true);
        setError(null);
        setSuccess(false);

        try {
            const { error } = await supabase.auth.updateUser({
                password: password
            });

            if (error) throw error;

            setSuccess(true);
            setTimeout(() => {
                navigate('/minha-conta');
            }, 3000);

        } catch (err: any) {
            setError(err.message || 'Erro ao atualizar a senha. O link pode ter expirado.');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="min-h-screen bg-brand-dark flex items-center justify-center p-4 font-sans text-gray-100">
            <div className="bg-black border border-brand-red/30 rounded-2xl shadow-[0_0_40px_rgba(220,38,38,0.15)] w-full max-w-md overflow-hidden animate-fade-in relative">
                <div className="p-8">
                    <div className="text-center mb-8 pt-4">
                        <h1 className="text-3xl font-black font-heading uppercase italic tracking-widest text-white">Nova Senha</h1>
                        <p className="text-gray-400 mt-2 font-medium">Crie uma nova senha de acesso forte e segura.</p>
                    </div>

                    {error && (
                        <div className="mb-4 p-3 bg-red-50 text-brand-red text-sm rounded-lg border border-red-100 font-medium">
                            {error}
                        </div>
                    )}

                    {success ? (
                        <div className="text-center">
                            <div className="mb-6 flex justify-center">
                                <div className="w-16 h-16 bg-green-500/20 rounded-full flex items-center justify-center border border-green-500/30">
                                    <CheckCircle className="w-8 h-8 text-green-500" />
                                </div>
                            </div>
                            <h2 className="text-xl font-bold text-white mb-2 font-heading uppercase tracking-wide">Senha Atualizada!</h2>
                            <p className="text-gray-400 mb-8">
                                Sua senha foi alterada com sucesso. Redirecionando para sua conta...
                            </p>
                        </div>
                    ) : (
                        <form onSubmit={handleSubmit} className="space-y-5">
                            <div>
                                <label className="block text-sm font-bold font-heading uppercase tracking-wider text-gray-300 mb-1.5">Nova Senha</label>
                                <div className="relative">
                                    <Lock className="absolute left-3 top-3 h-5 w-5 text-gray-500" />
                                    <input
                                        type="password"
                                        required
                                        className="w-full pl-10 pr-4 py-2.5 bg-brand-dark border border-brand-red/20 text-white rounded-lg focus:ring-2 focus:ring-brand-orange focus:border-brand-orange outline-none transition-all placeholder:text-gray-600"
                                        placeholder="******"
                                        value={password}
                                        onChange={(e) => setPassword(e.target.value)}
                                        minLength={6}
                                    />
                                </div>
                            </div>

                            <div>
                                <label className="block text-sm font-bold font-heading uppercase tracking-wider text-gray-300 mb-1.5">Confirmar Nova Senha</label>
                                <div className="relative">
                                    <Lock className="absolute left-3 top-3 h-5 w-5 text-gray-500" />
                                    <input
                                        type="password"
                                        required
                                        className="w-full pl-10 pr-4 py-2.5 bg-brand-dark border border-brand-red/20 text-white rounded-lg focus:ring-2 focus:ring-brand-orange focus:border-brand-orange outline-none transition-all placeholder:text-gray-600"
                                        placeholder="******"
                                        value={confirmPassword}
                                        onChange={(e) => setConfirmPassword(e.target.value)}
                                        minLength={6}
                                    />
                                </div>
                            </div>

                            <button
                                type="submit"
                                disabled={loading || !password || !confirmPassword}
                                className="w-full py-3.5 mt-4 bg-gradient-to-r from-brand-red to-brand-orange text-white rounded-lg font-black font-heading uppercase italic tracking-widest text-lg hover:shadow-[0_0_20px_rgba(220,38,38,0.4)] transition-all flex items-center justify-center gap-2 transform hover:-translate-y-0.5 disabled:opacity-75 disabled:cursor-not-allowed disabled:transform-none"
                            >
                                {loading ? <Loader2 className="w-5 h-5 animate-spin" /> : 'Atualizar Senha'}
                            </button>
                        </form>
                    )}
                </div>
            </div>
        </div>
    );
}

import { type PaymentMethod } from '../types';
// import { supabase } from '../lib/supabase';

// Interfaces para o Pagar.me (simplificadas)
interface PagarmeOrderInput {
    amount: number; // em centavos
    description: string;
    payment_method: PaymentMethod;
    card_hash?: string; // Token do cartão para cartão de crédito
    customer: {
        name: string;
        email: string;
        document: string; // CPF
        phones: {
            mobile_phone: {
                country_code: string;
                area_code: string;
                number: string;
            }
        }
    };
}

export const PagarmeService = {
    async createTransaction(input: PagarmeOrderInput): Promise<{ id: string; status: string; qrcode?: string; qrcode_url?: string }> {
        console.log('Chamando Edge Function pagarme-checkout via RAW FETCH...');

        // const { data: { session } } = await supabase.auth.getSession();
        // FORCE ANON KEY to avoid 401 errors with potential bad user tokens
        // We can revert this to use session token later if RLS requires it
        const token = import.meta.env.VITE_SUPABASE_ANON_KEY;
        console.log('Using Anon Key for Edge Function.');

        // Helper to handle potential trailing slash in env var
        const baseUrl = (import.meta.env.VITE_SUPABASE_URL || '').replace(/\/$/, '');
        const functionUrl = `${baseUrl}/functions/v1/pagarme-checkout`;

        try {
            const response = await fetch(functionUrl, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${token}`
                },
                body: JSON.stringify(input)
            });

            console.log('Edge Function Status:', response.status);

            const responseText = await response.text();
            console.log('Edge Function Raw Body:', responseText);

            if (!response.ok) {
                let errorMessage = `Erro HTTP ${response.status}`;
                try {
                    const errorJson = JSON.parse(responseText);
                    errorMessage = errorJson.error || errorMessage;
                } catch (e) {
                    errorMessage = responseText || errorMessage;
                }
                throw new Error(errorMessage);
            }

            const data = JSON.parse(responseText);

            // Check if the function returned a "soft" error (status 200 but success: false)
            if (data.error) {
                throw new Error(data.error);
            }

            return data;

        } catch (error: any) {
            console.error('Erro no Fetch:', error);
            throw error;
        }
    }
};

import { supabase } from '../lib/supabase';
import { type FightEvent, type Video } from '../types';

export const VideoService = {
    async getAll(): Promise<FightEvent[]> {
        try {
            const { data, error } = await supabase
                .from('videos')
                .select('*')
                .eq('is_active', true)
                .order('fight_date', { ascending: false });

            if (error) {
                console.error('Error fetching videos:', error);
                return [];
            }

            if (!data || data.length === 0) {
                return [];
            }

            return data.map(mapDatabaseVideoToFightEvent);
        } catch (error) {
            console.error('Unexpected error in getAll:', error);
            return [];
        }
    },

    async search(query: string, filters?: VideoFilters): Promise<FightEvent[]> {
        try {
            let queryBuilder = supabase
                .from('videos')
                .select('*')
                .eq('is_active', true);

            if (query) {
                queryBuilder = queryBuilder.ilike('title', `%${query}%`);
            }

            if (filters?.category) {
                queryBuilder = queryBuilder.eq('category', filters.category);
            }

            if (filters?.modality) {
                queryBuilder = queryBuilder.eq('modality', filters.modality);
            }

            const { data, error } = await queryBuilder.order('fight_date', { ascending: false });

            if (error) {
                console.error('Error searching videos:', error);
                return [];
            }

            return data?.map(mapDatabaseVideoToFightEvent) || [];
        } catch (error) {
            console.error('Error in search:', error);
            return [];
        }
    },

    async getBySlug(slug: string): Promise<FightEvent | null> {
        try {
            const { data, error } = await supabase
                .from('videos')
                .select('*')
                .eq('slug', slug)
                .eq('is_active', true)
                .single();

            if (error) {
                console.error('Error fetching video by slug:', error);
                return null;
            }

            return data ? mapDatabaseVideoToFightEvent(data) : null;
        } catch (error) {
            console.error('Error in getBySlug:', error);
            return null;
        }
    },

    async getMyVideos(userId: string): Promise<FightEvent[]> {
        try {
            const { data, error } = await supabase
                .from('order_items')
                .select(`
                    *,
                    videos (*),
                    orders!inner (status, user_id)
                `)
                .eq('orders.user_id', userId)
                .in('orders.status', ['paid', 'pending']);

            if (error) throw error;

            const paidItems = data?.filter(item => item.orders.status === 'paid') || [];

            return paidItems.map(item => mapDatabaseVideoToFightEvent(item.videos as Video));
        } catch (error) {
            console.error('Error fetching my videos:', error);
            return [];
        }
    },

    async getMyOrders(userId: string): Promise<any[]> {
        try {
            const { data, error } = await supabase
                .from('orders')
                .select(`
                    id,
                    created_at,
                    status,
                    total_amount,
                    payment_method,
                    pix_qr_code,
                    pix_qr_code_url,
                    order_items (
                        id,
                        order_id,
                        production_status,
                        production_form_data,
                        delivered_video_url,
                        videos ( title )
                    )
                `)
                .eq('user_id', userId)
                .order('created_at', { ascending: false });

            if (error) {
                console.error('Error fetching orders:', error);
                return [];
            }
            return data || [];
        } catch (error) {
            console.error('Error in getMyOrders:', error);
            return [];
        }
    },

    async getVideoSource(videoId: string): Promise<{ highlight_id: string | null, full_fight_id: string | null }> {
        try {
            const { data, error } = await supabase.rpc('get_my_video_access', { p_video_id: videoId });

            if (error) throw error;

            if (data && data.length > 0) {
                return data[0];
            }
            return { highlight_id: null, full_fight_id: null };
        } catch (error) {
            console.error('Error getting video source:', error);
            return { highlight_id: null, full_fight_id: null };
        }
    },

    async getByEventId(eventId: string, includeInactive = false): Promise<FightEvent[]> {
        try {
            let queryBuilder = supabase
                .from('videos')
                .select('*')
                .eq('event_id', eventId);

            if (!includeInactive) {
                queryBuilder = queryBuilder.eq('is_active', true);
            }

            const { data, error } = await queryBuilder.order('price_highlight', { ascending: false }); // Show main fights (usually more expensive or just order by title/schedule) possibly

            if (error) {
                console.error('Error fetching videos by event:', error);
                return [];
            }
            return data?.map(mapDatabaseVideoToFightEvent) || [];
        } catch (error) {
            console.error('Error in getByEventId:', error);
            return [];
        }
    },
};

export interface VideoFilters {
    category?: string;
    modality?: string;
}

function mapDatabaseVideoToFightEvent(video: Video): FightEvent {
    return {
        ...video,
        thumbnailUrl: video.teaser_url || 'https://via.placeholder.com/640x360?text=No+Image',
        description: `Evento: ${video.event_name} - ${video.modality}`
    };
}

// deno-lint-ignore-file
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2.39.3'

const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
}

Deno.serve(async (req) => {
  // Handle CORS preflight requests
  if (req.method === 'OPTIONS') {
    return new Response('ok', { headers: corsHeaders })
  }

  try {
    // Pagar.me sends webhook data as JSON
    const payload = await req.json()

    console.log("Recebendo Webhook do Pagar.me!", JSON.stringify(payload, null, 2))

    // We only care about specific events, primarily Order Paid.
    // The event type is usually something like 'order.paid' or 'charge.paid'
    const eventType = payload.type;
    const eventData = payload.data;

    if (!eventType || !eventData) {
      return new Response('Ignored - Invalid Payload Structure', { status: 200 })
    }

    let newStatus = null;
    let gatewayId = null;

    if (eventType === 'order.paid') {
      newStatus = 'paid';
      gatewayId = eventData.id; // Or charges[0].id depending on how it was saved
    } else if (eventType === 'charge.paid') {
      newStatus = 'paid';
      gatewayId = eventData.order.id; // Usually charge webhook links back to order
      // NOTE: Our checkout saves the charge.id as gateway_id. Let's try to match by charge ID if this is a charge event
      if (eventData.id) {
        gatewayId = eventData.id;
      }
    } else if (eventType.includes('failed') || eventType.includes('canceled')) {
      newStatus = 'failed';
      gatewayId = eventData.id;
    }

    // If we didn't determine a relevant status change, just return 200 OK so Pagar.me stops retrying
    if (!newStatus) {
      console.log(`Evento ignorado (não altera status para pago ou falho): ${eventType}`);
      return new Response('Ignored - Event Type Not Handled', { status: 200 })
    }

    // We need an elevated client (Service Role) to bypass RLS and update orders table securely
    const supabaseUrl = Deno.env.get('SUPABASE_URL')
    const supabaseServiceRoleKey = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')

    if (!supabaseUrl || !supabaseServiceRoleKey) {
      console.error('Missing ENV Vars (SUPABASE_URL or SUPABASE_SERVICE_ROLE_KEY)')
      return new Response('Server Config Error', { status: 500 })
    }

    const supabase = createClient(supabaseUrl, supabaseServiceRoleKey)

    // Find the order that matches the gateway_id (which might be the order.id or charge.id)
    // Since our createTransaction saves `charge.id` as `gateway_id`, we try that first
    let orderToUpdateId = null;

    // Tenta achar com o charge.id
    const { data: ordersByGateway, error: findErr1 } = await supabase
      .from('orders')
      .select('id')
      .eq('gateway_id', eventData.id) // If event is charge.paid, data.id is the charge ID
      .limit(1);

    if (ordersByGateway && ordersByGateway.length > 0) {
      orderToUpdateId = ordersByGateway[0].id;
    } else if (eventData.order && eventData.order.id) {
      // Tenta achar com o order.id pai (caso o webhook seja charge.paid mas a gente tenha salvo order.id)
      const { data: ordersByOrder, error: findErr2 } = await supabase
        .from('orders')
        .select('id')
        .eq('gateway_id', eventData.order.id)
        .limit(1);

      if (ordersByOrder && ordersByOrder.length > 0) {
        orderToUpdateId = ordersByOrder[0].id;
      }
    }

    if (!orderToUpdateId) {
      console.error(`Pedido não encontrado no banco para o gateway_id: ${eventData.id} ou ${eventData.order?.id}`);
      return new Response('Order Not Found in DB', { status: 200 }); // Status 200 so Pagar.me knows we processed it, even if failed internally
    }

    console.log(`Atualizando Pedido ${orderToUpdateId} para status: ${newStatus}`);

    // Update the database
    const { error: updateErr } = await supabase
      .from('orders')
      .update({ status: newStatus })
      .eq('id', orderToUpdateId);

    if (updateErr) {
      console.error("Erro ao atualizar o pedido no banco:", updateErr);
      return new Response('Database Update Failed', { status: 500 })
    }

    console.log("Pedido atualizado com sucesso via Webhook!");

    // Pagar.me REQUIRES a 200 OK fast response, otherwise it will keep retrying and eventually disable the webhook
    return new Response(JSON.stringify({ received: true, updated_order: orderToUpdateId, status: newStatus }), {
      headers: { ...corsHeaders, "Content-Type": "application/json" },
      status: 200
    });

  } catch (error) {
    console.error('Webhook processing error:', error)
    return new Response(
      JSON.stringify({ error: error.message || 'Internal Server Error', success: false }),
      { headers: { ...corsHeaders, "Content-Type": "application/json" }, status: 500 },
    )
  }
})
